package mai; import ("fmt"; "net"; "time"; "os"); func main() { f,_ := os.OpenFile("log.txt", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644); defer f.Close(); target := "8.8.8.8:53"; start := time.Now(); _, err := net.DialTimeout("tcp", target, 2*time.Second); duration := time.Since(start); result := fmt.Sprintf("Time: %v | Latency: %v | Error: %v\n", time.Now().Format("15:04:05"), duration, err); fmt.Print(result); f.WriteString(result) }
